import{_ as e,c as a,o as l,ag as r}from"./chunks/framework.DZohcHco.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"content/biji/vue/index.md","filePath":"content/biji/vue/index.md","lastUpdated":1773557052000}'),i={name:"content/biji/vue/index.md"};function h(n,t,d,f,o,s){return l(),a("div",null,[...t[0]||(t[0]=[r('<hr><h3 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">章节</th><th style="text-align:left;">目录</th></tr></thead><tbody><tr><td style="text-align:left;">整体架构</td><td style="text-align:left;"><a href="./1.html">1. Vue3 设计思想</a> <br> <a href="./2.html">2. 开发环境搭建</a></td></tr><tr><td style="text-align:left;">响应式原理</td><td style="text-align:left;"><a href="./3.html">3. 响应式数据核心</a> <br> <a href="./4.html">4. Reactivity 模块</a> <br> <a href="./5.html">5. Ref 实现</a> <br> <a href="./6.html">6. Computed 实现原理</a> <br> <a href="./7.html">7. Watch &amp; WatchEffect</a></td></tr><tr><td style="text-align:left;">渲染原理</td><td style="text-align:left;"><a href="./8.html">8. 实现 runtime-dom</a> <br> <a href="./9.html">9. 实现 runtime-core</a></td></tr><tr><td style="text-align:left;">Diff 算法原理</td><td style="text-align:left;"><a href="./10.html">10. 实现 Diff 算法</a></td></tr><tr><td style="text-align:left;">组件渲染原理</td><td style="text-align:left;"><a href="./11.html">11. 实现 Text 和 Fragment</a> <br> <a href="./12.html">12. 实现组件渲染</a> <br> <a href="./13.html">13. 实现 setup 函数</a> <br> <a href="./14.html">14. 实现函数式组件</a> <br> <a href="./15.html">15. 依赖注入原理</a> <br> <a href="./16.html">16. 简化版 Ref 实现</a></td></tr><tr><td style="text-align:left;">其他实现原理</td><td style="text-align:left;"><a href="./17.html">17. 实现 Teleport</a> <br> <a href="./18.html">18. 实现 Transition</a> <br> <a href="./19.html">19. 实现 KeepAlive</a> <br> <a href="./20.html">20. 实现异步组件</a></td></tr><tr><td style="text-align:left;">模板编译原理</td><td style="text-align:left;"><a href="./21.html">21. 编译优化</a> <br> <a href="./22.html">22. 模板转化 AST 语法树</a> <br> <a href="./23.html">23. 代码转化</a> <br> <a href="./24.html">24. 代码生成</a></td></tr></tbody></table><hr><h3 id="关于本书的特色" tabindex="-1">关于本书的特色 <a class="header-anchor" href="#关于本书的特色" aria-label="Permalink to &quot;关于本书的特色&quot;">​</a></h3><ul><li><p>教程详细，带你构建自己的 Vue 库；</p></li><li><p>按 Git Tag 划分迭代步骤，记录每个功能的实现过程；</p></li></ul><hr><h3 id="学完本书你将收获" tabindex="-1">学完本书你将收获 <a class="header-anchor" href="#学完本书你将收获" aria-label="Permalink to &quot;学完本书你将收获&quot;">​</a></h3><p>Vue 是由卓越工程师们在数年时间内精心打造的库，其中必定蕴含了许多值得借鉴的经验和智慧。</p><p>如果你渴望更进一步，不仅仅停留在 API 的使用层面，而是追求更深入前端技术的探索，那么掌握 Vue 源码将成为你技能提升的极佳途径。</p><p>本书遵循 Vue 源码的核心思想，通俗易懂的解析 Vue 源码，带你从零实现 Vue 3.4 的核心功能，学完本书，你将有这些收获：</p><ol><li>详解 Vue3 设计理念及整体架构思想，搭建 Vue3 开发环境。</li><li>手写 Vue3 响应式原理，包括 reactive、effect、watch、computed、ref 等核心 API。</li><li>掌握 Vue3 源码调试技巧，深入理解 Vue3 的内部机制。</li><li>深入理解自定义渲染器原理及在 Runtime DOM 中的属性和事件处理方法。</li><li>探索虚拟 DOM 的概念，手写 Vue3 中的 diff 算法以及最长递增子序列实现原理。</li><li>手写 Vue3 组件的实现原理，深入理解组件的渲染、挂载流程，以及异步渲染的机制。</li><li>掌握 Vue3 中生命周期的原理，以及 props、emit、slot、provide、inject 等功能的实现机制。</li><li>学习编译优化技巧，掌握 patchFlags、blockTree 等实现靶向更新的方法。</li><li>手写 Vue3 编译原理，掌握解析器、AST 语法树的优化、代码生成原理。</li><li>理解 Vue3 中的异步组件、函数式组件、Teleport、keep-alive、Transition 组件的实现原理。</li></ol><hr><h3 id="互动勘误" tabindex="-1">互动勘误 <a class="header-anchor" href="#互动勘误" aria-label="Permalink to &quot;互动勘误&quot;">​</a></h3><p>如果书中文章有所遗漏，欢迎点击所在页面左下角的按钮进行修改，感谢您的支持与帮助。</p><hr><h3 id="版权声明" tabindex="-1">版权声明 <a class="header-anchor" href="#版权声明" aria-label="Permalink to &quot;版权声明&quot;">​</a></h3><p>本栏目原作者是 <a href="https://github.com/2xiao" target="_blank" rel="noreferrer">@2xiao</a> 。</p><p>本作品采用 知识署名-非商业性使用-禁止演绎 （BY-NC-ND） 4.0 国际许可<a href="https://creativecommons.org/licenses/by-nc-nd/4.0/legalcode.zh-Hans" target="_blank" rel="noreferrer">协议</a> 进行许可。</p><p>只要保持原作者署名和非商用，您可以自由地阅读、分享、修改本书。</p><p><a href="./1.html">开始阅读 -&gt;</a></p>',21)])])}const c=e(i,[["render",h]]);export{p as __pageData,c as default};
